// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./PlantBatch.sol";

contract MedicineBatch {
    PlantBatch public plantContract;

    struct MedicineData {
        string medicineName;
        uint256 plantBatchId;      // Link to agriculture data
        string manufacturer;
        uint256 expiryDate;
        string batchNumber;
        bool isSafeForPatients;
    }

    mapping(uint256 => MedicineData) public medicineBatches;
    uint256 public medicineCounter;

    event MedicineBatchCreated(uint256 medicineId, uint256 plantBatchId, string medicineName);

    constructor(address _plantContractAddress) {
        plantContract = PlantBatch(_plantContractAddress);
    }

    function createMedicineBatch(
        string memory _medicineName,
        uint256 _plantBatchId,
        string memory _manufacturer,
        uint256 _expiryDate,
        string memory _batchNumber
    ) public {
        // Get plant data and check quality
        PlantBatch.PlantData memory plant = plantContract.getPlantBatch(_plantBatchId);
        
        bool safe = plant.isApproved && plant.aiQualityScore >= 70;

        medicineCounter++;
        medicineBatches[medicineCounter] = MedicineData({
            medicineName: _medicineName,
            plantBatchId: _plantBatchId,
            manufacturer: _manufacturer,
            expiryDate: _expiryDate,
            batchNumber: _batchNumber,
            isSafeForPatients: safe
        });

        emit MedicineBatchCreated(medicineCounter, _plantBatchId, _medicineName);
    }

    function getMedicineBatch(uint256 _medicineId) public view returns (MedicineData memory) {
        return medicineBatches[_medicineId];
    }

    // 🔥 This is the key function for the jury: Full Farm-to-Medicine Traceability
    function getFullTraceability(uint256 _medicineId) public view returns (
        MedicineData memory medicine,
        PlantBatch.PlantData memory plant
    ) {
        MedicineData memory med = medicineBatches[_medicineId];
        PlantBatch.PlantData memory plt = plantContract.getPlantBatch(med.plantBatchId);
        return (med, plt);
    }
}

